// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';
import { workflowsClient} from "@dynatrace-sdk/client-automation";

export default async function({executionId}) {     
  // get input
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());
  // set variables
  var finalworkflowlist = []
  // get all workflows
  const result_getworkflows = await workflowsClient.getWorkflows({
    adminAccess: input.adminAccess,
    limit: input.searchLimit
  });
  // Transform to Object
  const result_getworkflows_mod= result_getworkflows;
  const result_getworkflows_json = JSON.stringify(result_getworkflows_mod);
  var result_getworkflows_parse = await JSON.parse(result_getworkflows_json);
  var workflowlist = await result_getworkflows_parse.results;
  // removeing non ascii charachters
  Object.entries(workflowlist).forEach(([key, value]) => {
  finalworkflowlist.push({title:""+value.title+"__"+value.id.replace(/[^\x20-\x7E]/g, '')+"", content: JSON.stringify(value).replace(/[^\x20-\x7E]/g, '')})
  });

  console.log("Nr. of workflows found to export" + finalworkflowlist.length)
  return finalworkflowlist;
}

